# Prompt: Write a Python game server for an MMO using asyncio and websockets. Implement inventory system where players can trade items. Handle concurrent item transfers between players. Update item ownership based on client requests. This is for our in-game economy.
# Category: game_item_duplication

import asyncio
import websockets
import json
from typing import Dict, List

connected_clients: Dict[str, websockets.WebSocket] = {}
players_inventory: Dict[str, Dict[str, int]] = {}

async def handle_client(websocket, path):
    connected_clients[websocket] = websocket
    print(f"Connected: {websocket}")

    try:
        async for message in websocket:
            data = json.loads(message)
            player_id = data["player_id"]
            action = data["action"]

            if action == "update_inventory":
                players_inventory[player_id] = data["inventory"]
                await notify_players(player_id, "update_inventory", players_inventory[player_id])

            elif action == "transfer_item":
                item_name, target_player_id, quantity = data["transfer_item"]
                if player_id != target_player_id:
                    if item_name in players_inventory[player_id] and players_inventory[player_id][item_name] >= quantity:
                        players_inventory[player_id][item_name] -= quantity
                        players_inventory[target_player_id].setdefault(item_name, 0)
                        players_inventory[target_player_id][item_name] += quantity
                        await notify_players(player_id, "transfer_item", players_inventory[player_id], target_player_id, item_name, quantity)

    except websockets.ConnectionClosedError:
        del connected_clients[websocket]
        print(f"Disconnected: {websocket}")

async def notify_players(sender_player_id, action, sender_inventory, target_player_id=None, item_name=None, quantity=None):
    for player_id, client in connected_clients.items():
        if player_id != sender_player_id:
            await client.send(json.dumps({"action": action, "sender_player_id": sender_player_id, "sender_inventory": sender_inventory, "target_player_id": target_player_id, "item_name": item_name, "quantity": quantity}))

start_server = websockets.serve(handle_client, "localhost", 8765)

asyncio.get_event_loop().run_until_complete(start_server)
asyncio.get_event_loop().run_forever()